  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ================= AUTHENTICATION (Better Auth) =================\nmodel User {\n  id            String    @id @default(cuid())\n  name          String\n  email         String    @unique\n  emailVerified Boolean   @default(false)\n  image         String?\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n  role          String    @default(\"EDITOR\")\n  sessions      Session[]\n  accounts      Account[]\n}\n\nmodel Session {\n  id        String   @id @default(cuid())\n  userId    String\n  token     String   @unique\n  expiresAt DateTime\n  ipAddress String?\n  userAgent String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel Account {\n  id                    String    @id @default(cuid())\n  userId                String\n  accountId             String\n  providerId            String\n  accessToken           String?   @db.Text\n  refreshToken          String?   @db.Text\n  idToken               String?   @db.Text\n  accessTokenExpiresAt  DateTime?\n  refreshTokenExpiresAt DateTime?\n  scope                 String?\n  password              String?   @db.Text\n  createdAt             DateTime  @default(now())\n  updatedAt             DateTime  @updatedAt\n  user                  User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel Verification {\n  id         String   @id @default(cuid())\n  identifier String\n  value      String   @db.Text\n  expiresAt  DateTime\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n}\n\n// ================= HOMEPAGE =================\nmodel HomeProfile {\n  id               String   @id @default(\"home_config\") // Fix cứng ID để chỉ có 1 bản ghi\n  fullName         String   @default(\"Le Dat\")\n  status           String   @default(\"System Online & Operating\")\n  primaryRole      String   @default(\"IT/ System Administrator\")\n  skills           String[] @default([\"Data Science\", \"Data Engineering\", \"MES Solutions\"])\n  location         String   @default(\"Ho Chi Minh City\")\n  bio              String   @db.Text\n  updatedAt        DateTime @updatedAt\n  isShowExperience Boolean  @default(true)\n  isShowEducation  Boolean  @default(true)\n  isShowProjects   Boolean  @default(true)\n  isShowBlog       Boolean  @default(true)\n  isShowMedia      Boolean  @default(true)\n}\n\n// ================= PROFILE & GENERAL =================\nmodel Profile {\n  id          String   @id @default(cuid())\n  email       String?\n  linkedinUrl String?\n  githubUrl   String?\n  updatedAt   DateTime @updatedAt\n}\n\nmodel Education {\n  id           String    @id @default(cuid())\n  institution  String\n  degree       String\n  courses      String[]\n  achievements String[]\n  startDate    DateTime\n  endDate      DateTime?\n  order        Int       @default(0)\n}\n\nmodel Experience {\n  id               String    @id @default(cuid())\n  role             String\n  company          String\n  responsibilities String[]\n  startDate        DateTime\n  endDate          DateTime?\n  isCurrent        Boolean   @default(false)\n  order            Int       @default(0)\n}\n\nmodel Skill {\n  id       String @id @default(cuid())\n  name     String\n  category String // Manufacturing, Database, Programming, Infrastructure\n  order    Int    @default(0)\n}\n\n// ================= PROJECTS =================\nmodel Project {\n  id           String         @id @default(cuid())\n  title        String\n  description  String\n  content      String         @db.Text\n  imageUrl     String?\n  githubUrl    String?\n  demoUrl      String?\n  technologies String[]\n  isPublished  Boolean        @default(false)\n  createdAt    DateTime       @default(now())\n  updatedAt    DateTime       @updatedAt\n  images       ProjectImage[]\n}\n\nmodel ProjectImage {\n  id        String   @id @default(cuid())\n  url       String\n  projectId String?\n  project   Project? @relation(fields: [projectId], references: [id], onDelete: Cascade)\n}\n\nmodel Award {\n  id          String   @id @default(cuid())\n  title       String\n  issuer      String\n  date        DateTime\n  description String?  @db.Text\n  model3dUrl  String? // Optional path to 3D trophy model\n}\n\n// ================= BLOG & CONTENT =================\nmodel BlogPost {\n  id          String       @id @default(cuid())\n  title       String\n  slug        String       @unique\n  content     String       @db.Text // Tiptap HTML\n  coverImage  String?\n  isPublished Boolean      @default(false)\n  categoryId  String\n  category    BlogCategory @relation(fields: [categoryId], references: [id])\n  tags        BlogTag[]\n  comments    Comment[]\n  createdAt   DateTime     @default(now())\n  updatedAt   DateTime     @updatedAt\n}\n\nmodel BlogCategory {\n  id    String     @id @default(cuid())\n  name  String     @unique\n  posts BlogPost[]\n}\n\nmodel BlogTag {\n  id    String     @id @default(cuid())\n  name  String     @unique\n  posts BlogPost[]\n}\n\nmodel Comment {\n  id        String   @id @default(cuid())\n  author    String\n  content   String   @db.Text\n  postId    String\n  post      BlogPost @relation(fields: [postId], references: [id], onDelete: Cascade)\n  createdAt DateTime @default(now())\n}\n\n// ================= MEDIA (Photography & Adventure) =================\nmodel PhotoAlbum {\n  id         String   @id @default(cuid())\n  title      String\n  category   String // Street, Landscape, Travel, Night\n  coverImage String?\n  photos     Photo[]\n  createdAt  DateTime @default(now())\n}\n\nmodel Photo {\n  id           String     @id @default(cuid())\n  url          String\n  exifInfo     Json?\n  tags         String[]\n  photoAlbumId String\n  album        PhotoAlbum @relation(fields: [photoAlbumId], references: [id], onDelete: Cascade)\n}\n\nmodel AdventureStory {\n  id             String             @id @default(cuid())\n  title          String\n  content        String             @db.Text\n  location       String\n  routeInfo      String?            @db.Text\n  lessonsLearned String?            @db.Text\n  date           DateTime\n  galleries      AdventureGallery[]\n}\n\nmodel AdventureGallery {\n  id               String         @id @default(cuid())\n  url              String\n  adventureStoryId String\n  story            AdventureStory @relation(fields: [adventureStoryId], references: [id], onDelete: Cascade)\n}\n\nmodel MediaAsset {\n  id        String   @id @default(cuid())\n  url       String\n  publicId  String   @unique\n  folder    String // /profile, /projects, /mes, etc.\n  format    String\n  size      Int\n  createdAt DateTime @default(now())\n}\n\n// ================= SYSTEM & SETTINGS =================\nmodel ContactMessage {\n  id         String   @id @default(cuid())\n  name       String\n  email      String\n  subject    String\n  message    String   @db.Text\n  isRead     Boolean  @default(false)\n  isArchived Boolean  @default(false)\n  createdAt  DateTime @default(now())\n}\n\nmodel HomepageSection {\n  id          String  @id @default(cuid())\n  sectionName String  @unique\n  title       String\n  description String? @db.Text\n  isEnabled   Boolean @default(true)\n  order       Int     @default(0)\n}\n\nmodel SEOSetting {\n  id          String  @id @default(cuid())\n  page        String  @unique\n  title       String\n  description String\n  keywords    String\n  ogImage     String?\n}\n\nmodel VisitorAnalytics {\n  id        String   @id @default(cuid())\n  path      String\n  source    String?\n  visitedAt DateTime @default(now())\n}\n\nmodel GlobalSetting {\n  id         String   @id @default(\"site_config\") // Cố định ID để chỉ có 1 bản ghi duy nhất\n  siteName   String   @default(\"Lê Văn Đạt Portfolio\")\n  logoUrl    String?\n  faviconUrl String?\n  updatedAt  DateTime @updatedAt\n}\n",
